-- POLIZAS VIGENTES 
--

DROP procedure sp_jean02am;
CREATE procedure sp_jean02am()
RETURNING CHAR(5),char(10);--REFERENCES TEXT;

DEFINE _no_poliza	 	CHAR(10);
DEFINE _no_documento    CHAR(20);
DEFINE _cod_contratante char(10);
DEFINE _n_contratante,_n_producto  	CHAR(50);
DEFINE _cnt  			integer;
DEFINE _cod_producto    char(10);
DEFINE lblb_descripcion REFERENCES TEXT;
define v_filtros        varchar(255);
define _no_unidad       char(5);
define _vigencia_inic   date;
define _cod_no_renov    char(3);

{	foreach
		select no_unidad,
		       no_poliza
	      into _no_unidad,
		       _no_poliza
 	      from emipouni 
		 where no_poliza = '2956308'
		 and no_unidad = '00001'
		
		call sp_blob_emipode2(_no_poliza ,_no_unidad) returning lblb_descripcion;
		
		let _cod_producto = 'pio *';
		
		--let lblb_descripcion = replace(lblb_descripcion,'01-2718726','01-2882619');
		
		let _cod_producto = replace(_cod_producto,'*','-A');
		
		select * from emipode2 _no_poliza
		where no_poliza = '2956308'
		and no_unidad = '00001'
		into temp pru1;
		
		update pru1
		set descripcion = lblb_descripcion;
		
		return _no_unidad,_cod_producto with resume;
		
	end foreach	}
	
